  ('locality-6e2f88c7-moex-00319', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '繼承人逾公告期間未辦理繼承登記之土地，經直轄市政府列冊管理期滿後，移交財政部國有財產 署公開標售，該土地之合法使用人對其使用範圍，依土地法行使優先購買權並確認優先購買權存 在，應如何救濟？', '["向普通法院提起民事訴訟", "提起撤銷訴願或撤銷訴訟", "提起課予義務訴願或課予義務訴訟", "向行政法院聲請暫時停止執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "d9613371e0ed", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00320', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '臺灣土地銀行依公司法及銀行法等規定設立，以經營各項銀行業務，發展國民經濟建設為宗旨。 其組織之屬性為：', '["行政法人", "私法人", "公法人", "行政機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "d9613371e0ed", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00321', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '行政程序法第11條第1項規定，行政機關之管轄權，依其組織法規或其他行政法規定之。此乃下 列那一原則之表現？', '["管轄恆定原則", "管轄法定原則", "依法行政原則", "法律保留原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "d9613371e0ed", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00322', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依據公務人員保障法規定之復審程序，下列敘述何者錯誤？', '["非現職人員基於原公務人員身分之公法上財產請求權遭侵害時，亦得提起復審", "公務人員之名譽權生前遭受侵害者，其遺族亦得提起復審", "復審之提起，應自行政處分達到之次日起30日內為之", "復審事件涉及地方自治事項者，公務人員保障暨培訓委員會僅就行政處分之合法性進行審查決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "d9613371e0ed", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00323', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '關於公務人員考績，下列敘述何者正確？', '["年終考績丙等，留原俸級", "年終考績以100分為滿分，分甲、乙、丙、丁、戊五等", "一次記二大功者，晉本俸一級，並給與2個月俸給總額之獎金", "一次記二大過者，停職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "d9613371e0ed", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00324', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '依公務人員保障法之規定，關於公務人員之服從義務，下列敘述何者正確？', '["凡長官在其監督範圍內發布之命令，無論是否合法，公務人員皆有服從義務", "長官在其監督範圍內發布之命令，公務人員如認為違反行政法規者，自得拒絕服從", "長官所發布之命令有違反刑事法律者，公務人員無服從之義務", "公務人員認長官之命令違法者，於履行報告義務後，不待長官書面下達，即應服從"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "d9613371e0ed", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
  ('locality-6e2f88c7-moex-00325', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-110-3082b5f1', 'sub-locality-6e2f88c7-05', NULL, 'single_choice', '關於公務員懲戒法之適用範圍與對象，下列敘述何者錯誤？', '["非執行職務之違法行為，若嚴重損害政府之信譽亦應受懲戒", "公務員之行為非出於故意或過失者，不受懲戒", "適用對象包括政務人員", "不適用於退休或離職之公務員於任職期間之行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:49+00:00", "source_pdf_sha1": "d9613371e0ed", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "315", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL)
